const ProductList = ({ products }) => {
  const addToCart = useCartStore((state) => state.addToCart);

  // useCallback stabilise la fonction entre les renders
  const handleAddToCart = useCallback((productId: string) => {
    addToCart(productId);
  }, [addToCart]); // addToCart est stable si le store est bien configuré

  return (
    <div className="grid">
      {products.map(product => (
        <MemoizedProductCard 
          key={product.id} 
          product={product} 
          onAddToCart={handleAddToCart}
        />
      ))}
    </div>
  );
};

// React.memo avec fonction de comparaison personnalisée (optionnelle)
const ProductCard = React.memo(({ product, onAddToCart }) => {
  return (
    <div className="border p-4">
      <h3>{product.name}</h3>
      <p>{product.price} €</p>
      <button onClick={() => onAddToCart(product.id)}>Ajouter</button>
    </div>
  );
}, (prevProps, nextProps) => {
  // Comparaison personnalisée pour éviter le re-render si seules des props non pertinentes changent
  return prevProps.product.id === nextProps.product.id &&
         prevProps.product.price === nextProps.product.price &&
         prevProps.product.name === nextProps.product.name;
});

const MemoizedProductCard = React.memo(ProductCard);
```

**Explication des optimisations :**
1. `React.memo` empêche le re-render du composant enfant si ses props n'ont pas changé
2. `useCallback` garantit que `handleAddToCart` a la même référence entre les renders (sauf si `addToCart` change)
3. La fonction de comparaison personnalisée permet un contrôle fin : on ignore par exemple les propriétés de `product` qui ne sont pas utilisées dans le rendu

```tsx
import { FixedSizeList as List } from 'react-window';
import { useCallback } from 'react';
import { useCartStore } from '@/stores/cartStore';

// Composant pour chaque ligne virtuelle
const ProductRow = ({ index, style, data }) => {
  const { products, onAddToCart } = data;
  const product = products[index];

  return (
    <div style={style} className="flex items-center justify-between border-b p-3">
      <div>
        <h3 className="font-semibold">{product.name}</h3>
        <p className="text-sm text-gray-600">{product.price} €</p>
      </div>
      <button 
        onClick={() => onAddToCart(product.id)}
        className="bg-blue-500 text-white px-3 py-1 rounded"
      >
        Ajouter
      </button>
    </div>
  );
};

// Composant principal avec virtualisation
const VirtualizedProductList = ({ products }) => {
  const addToCart = useCartStore((state) => state.addToCart);

  // useCallback stabilise la fonction passée à chaque ligne
  const handleAddToCart = useCallback((productId: string) => {
    addToCart(productId);
  }, [addToCart]);

  // Données partagées entre toutes les lignes (évite les props individuelles)
  const itemData = {
    products,
    onAddToCart: handleAddToCart,
  };

  return (
    <List
      height={600}           // Hauteur visible du conteneur
      itemCount={products.length}
      itemSize={120}         // Hauteur fixe de chaque ligne
      width="100%"
      itemData={itemData}    // Props partagées
    >
      {ProductRow}
    </List>
  );
};

export default VirtualizedProductList;
```

**Explication :**
- `FixedSizeList` ne rend que les lignes visibles (environ 5-10 au lieu de 10 000)
- `itemData` permet de passer des données partagées à toutes les lignes sans les inclure dans chaque `item` individuel
- `onAddToCart` est mémorisé avec `useCallback` pour éviter de recréer la fonction à chaque render du parent
- Le composant `ProductRow` reçoit `style` (position absolue relative) que react-window fournit automatiquement

```tsx
import { useState, useMemo, useCallback } from 'react';

const ProductCatalog = ({ products }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [minPrice, setMinPrice] = useState(0);
  const [maxPrice, setMaxPrice] = useState(1000);

  // useMemo : le filtrage n'est recalculé que lorsque products, searchTerm, minPrice ou maxPrice changent
  const filteredProducts = useMemo(() => {
    console.log('Filtrage recalculé');
    return products.filter(product => {
      const matchesSearch = product.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesPrice = product.price >= minPrice && product.price <= maxPrice;
      return matchesSearch && matchesPrice;
    });
  }, [products, searchTerm, minPrice, maxPrice]);

  // useCallback : les fonctions sont stables entre les renders
  const handleSearchChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    setSearchTerm(e.target.value);
  }, []);

  const handlePriceChange = useCallback((min: number, max: number) => {
    setMinPrice(min);
    setMaxPrice(max);
  }, []);

  return (
    <div>
      <input 
        type="text" 
        value={searchTerm} 
        onChange={handleSearchChange}
        placeholder="Rechercher..."
      />
      <PriceRangeSlider onPriceChange={handlePriceChange} />
      <ProductList products={filteredProducts} />
    </div>
  );
};
```

**Gain de performance :** Sans `useMemo`, le filtrage serait exécuté à chaque render (y compris lorsque le parent se re-rend). Avec `useMemo`, le filtrage ne s'exécute que lorsqu'une des dépendances change, ce qui est essentiel pour des listes de plusieurs milliers d'éléments.
